Here are the public test cases for feature1_plain_reset_and_conceal:
{
  "description": "Render ordinary text, reset-only input, and concealed segments so that visible text is preserved while hidden ANSI text is omitted unless it is an embedded console note marker.",
  "cases": [
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": ""
      },
      "expected_output": ""
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "line"
      },
      "expected_output": "line"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[0m\u001b[K"
      },
      "expected_output": ""
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "there is concealed text here, \u001b[8mCONCEAL\u001b[0m, and it should vanish."
      },
      "expected_output": "there is concealed text here, , and it should vanish."
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "there is a ConsoleNote here, \u001b[8mha:CONSOLENOTE\u001b[0m, and it should be left untouched."
      },
      "expected_output": "there is a ConsoleNote here, \u001b[8mha:CONSOLENOTE\u001b[0m, and it should be left untouched."
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "(\u001b(0)"
      },
      "expected_output": "()"
    }
  ]
}

Here are the public test cases for feature2_text_attributes:
{
  "description": "Render ANSI text-style attributes into nested HTML markup and close each style when its matching reset code is received.",
  "cases": [
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[1mhello world"
      },
      "expected_output": "<b>hello world</b>"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[4mhello world"
      },
      "expected_output": "<u>hello world</u>"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[21mhello world"
      },
      "expected_output": "<span style=\"border-bottom: 3px double;\">hello world</span>"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[3mhello world\u001b[23mnormal"
      },
      "expected_output": "<i>hello world</i>normal"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[9mhello world\u001b[29mnormal"
      },
      "expected_output": "<span style=\"text-decoration: line-through;\">hello world</span>normal"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[51mhello world\u001b[54mnormal"
      },
      "expected_output": "<span style=\"border: 1px solid;\">hello world</span>normal"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[53mhello world\u001b[55mnormal"
      },
      "expected_output": "<span style=\"text-decoration: overline;\">hello world</span>normal"
    },
    {
      "input": {
        "operation": "render_html",
        "palette": "xterm",
        "text": "\u001b[94;2mlightblue and also faint\u001b[0m"
      },
      "expected_output": "<span style=\"color: #4682B4;\"><span style=\"font-weight: lighter;\">lightblue and also faint</span></span>"
    }
  ]
}

